    "faction_id": 56,
    "type": "ploy",
    "name": "FRIGHTENING ONSLAUGHT",
    "cost": 1,
    "description": "Use this firefight ploy after a friendly GELLERPOX INFECTED NIGHTMARE HULK operative performs the Fight action, if it isn't incapacitated. It can immediately perform a free Fight action.",
    "version": null,
