    "faction_id": 31,
    "type": "equipment",
    "name": "GORY TOTEM",
    "cost": 0,
    "description": "Before the battle, you can set up one of your Gory Totem markers wholly within your territory and more than 2\" from other markers (excluding your Bloody Cadaver marker). Whenever an enemy operative within 3\" of your Gory Totem marker is shooting, fighting or retaliating, your opponent cannot re-roll their attack dice.",
    "version": null,
    "subtype": null
