    "faction_id": 57,
    "type": "faction_rules",
    "name": "BULWARK IMPERATIVE",
    "cost": 0,
    "description": "Optimisation: Normal Dmg of 3 or more inflicts 1 less damage on HUNTER CLADE friendly operatives.\n\nDeprecation: Subtract 1\" from the Move stat of friendly HUNTER CLADE operatives.",
    "version": null,
