    "weapons_json": "[{\"name\":\"Lasgun\",\"atk\":\"4\",\"hit\":\"4+\",\"dmg\":\"2/3\",\"wr\":\"–\"},{\"name\":\"Fists\",\"atk\":\"3\",\"hit\":\"4+\",\"dmg\":\"2/3\",\"wr\":\"–\"}]",
    "abilities_json": "[{\"name\":\"SIGNAL (1AP)\",\"description\":\"Support: Select one other friendly BROOD BROTHER BROODGUARD operative visible to and within 6\\\" of this operative. Until the end of that operative's next activation, add 1 to its APL stat.\\n\\nThis operative cannot perform this action while within control Range of an enemy operative.\"},{\"name\":\"JAM (1/2AP)\",\"description\":\"Select one ready enemy operative that's a valid target for this operative, or visible to this operative instead if you spend 1 additional AP. Roll one D6. Until the end of the turning point, that enemy operative cannot be activated or perform actions until it's the last enemy operative to be activated, or until your opponent has activated a number of enemy operatives after this action equal to the result of the D6 (whichever comes first).\\n\\nThis operative cannot perform this action while within control Range of an enemy operative.\"}]",
    "version": null,
    "keywords": "BROOD BROTHER, TYRANID, GENESTEALER CULT, BROODGUARD, VOX-OPERATOR"
